      it('should go to the last hour of the current morning when a value in the first hour is provided', () => {
        testFieldKeyPress({
          format: adapter.formats.fullTime12h,
          defaultValue: adapter.date('2022-06-15T00:12:25'),
          key: 'ArrowDown',
          expectedValue: '11:12 AM',
        });
